import React, { useState, useEffect } from 'react';
import {
  CButton,
  CModal,
  CModalHeader,
  CModalTitle,
  CModalBody,
  CModalFooter,
  CForm,
  CCol,
  CFormLabel,
  CFormFeedback,
  CFormInput,
  CFormSelect,
  CFormTextarea,
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import { cilPen } from '@coreui/icons';
import PropTypes from 'prop-types';
import i18n from 'src/i18n';
import { settingsAppointments } from 'src/services/standardUsers/index';
import { settingsConfigs } from 'src/services/SupperSettings';

const initialAppointmentState = {
  client_code: '',
  client_name: '',
  client_contact: '',
  date: '',
  time: '',
  duration: '',
  hardware: '',
  software: '',
  meeting_reason: '',
  description: '',
};

const AppointmentsC = ({ refresh, selectedAppointments }) => {
  const [visible, setVisible] = useState(false);
  const [validated, setValidated] = useState(false);
  const [appointment, setAppointment] = useState(initialAppointmentState);
  const [customers, setCustomers] = useState([]);

  useEffect(() => {
    setAppointment(selectedAppointments || initialAppointmentState);
  }, [selectedAppointments]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const form = e.currentTarget;
    setValidated(true);

    if (!form.checkValidity()) {
      e.stopPropagation();
      return;
    }

    const result = await settingsAppointments.addAppointments(appointment, 'entity/appointment');

    if (result) {
      setVisible(false);
      setValidated(false);
      setAppointment(initialAppointmentState);
      refresh();
    }
  };

  const handleChange = (field) => (e) => {
    setAppointment({ ...appointment, [field]: e.target.value });
  };

  const openModal = async () => {
    try {
      const result = await settingsConfigs.getConfig('customers');
      if (result?.data) {
        setCustomers(result.data);
      }
      alert("Reste Integaration API")
    } catch (err) {
      console.error('Failed to fetch customers', err);
    }
    setVisible(true);
  };

  const selectListCustomers = (attribuit, value) => {
    const customer = customers.find(cust => cust[attribuit] === value);

    if (customer) {
      console.log("Customer found:", customer);
      setAppointment((prev) => ({
        ...prev,
        customerId: customer.id,
        client_code: customer.code || '',
        client_name: customer.username || '',
        client_contact: customer.phone_number || '', // adjust keys as per your API response
      }));
    } else {
      alert("No customer found with the given attribute.");
        setAppointment((prev) => ({
        ...prev,
        customerId: "",
        client_code: '',
        client_name: '',
        client_contact:'', // adjust keys as per your API response
      }));
    }
  };

  return (
    <>
      <CButton color="primary" onClick={openModal}>
        <CIcon icon={cilPen} /> {i18n.t('addAppointmentTitle')}
      </CButton>

      <CModal alignment="center" visible={visible} onClose={() => setVisible(false)}>
        <CModalHeader onClose={() => setVisible(false)}>
          <CModalTitle>{i18n.t('addAppointmentTitle')}</CModalTitle>
        </CModalHeader>
        <CModalBody>
          <CForm className="row g-3 needs-validation" noValidate validated={validated} onSubmit={handleSubmit}>
            <CCol md={3}>
              <CFormLabel>{i18n.t('clientCode')}</CFormLabel>
            </CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_code} onChange={handleChange('client_code')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3} className="d-flex align-items-end">
              <div className="w-100">
                <CButton color="primary" onClick={() => selectListCustomers("code", appointment.client_code)} className="w-100">
                  {i18n.t('search')}
                </CButton>
              </div>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('clientName')}</CFormLabel>
            </CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_name} onChange={handleChange('client_name')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3} className="d-flex align-items-end">
              <div className="w-100">
                <CButton color="primary" onClick={() => selectListCustomers("username", appointment.client_name)} className="w-100">
                  {i18n.t('search')}
                </CButton>
              </div>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('clientContact')}</CFormLabel>
            </CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_contact} onChange={handleChange('client_contact')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3} className="d-flex align-items-end">
              <div className="w-100">
                <CButton color="primary" onClick={() => selectListCustomers("phone_number", appointment.client_contact)} className="w-100">
                  {i18n.t('search')}
                </CButton>
              </div>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('date')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput type="date" value={appointment.date} onChange={handleChange('date')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('time')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput type="time" value={appointment.time} onChange={handleChange('time')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('duration')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput type="number" value={appointment.duration} onChange={handleChange('duration')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('hardware')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.hardware} onChange={handleChange('hardware')} required>
                <option value="">{i18n.t('selectOption')}</option>
                <option>{i18n.t('hardwareOption1')}</option>
                <option>{i18n.t('hardwareOption2')}</option>
                <option>{i18n.t('hardwareOption3')}</option>
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3}>
              <CFormLabel>{i18n.t('software')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.software} onChange={handleChange('software')} required>
                <option value="">{i18n.t('selectOption')}</option>
                <option>{i18n.t('softwareOption1')}</option>
                <option>{i18n.t('softwareOption2')}</option>
                <option>{i18n.t('softwareOption3')}</option>
                <option>{i18n.t('softwareOption4')}</option>
                <option>{i18n.t('softwareOption5')}</option>
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}>
              <CFormLabel>{i18n.t('meetingReason')}</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.meeting_reason} onChange={handleChange('meeting_reason')} required>
                <option value="">{i18n.t('selectOption')}</option>
                <option>{i18n.t('reasonOption1')}</option>
                <option>{i18n.t('reasonOption2')}</option>
                <option>{i18n.t('reasonOption3')}</option>
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={12}>
              <CFormLabel>{i18n.t('description')}</CFormLabel>
              <CFormTextarea rows={4} value={appointment.description} onChange={handleChange('description')} />
            </CCol>

            <CModalFooter>
              <CButton color="secondary" onClick={() => setVisible(false)}>
                {i18n.t('closeButton')}
              </CButton>
              <CButton color="primary" type="submit">
                {i18n.t('saveButton')}
              </CButton>
            </CModalFooter>
          </CForm>
        </CModalBody>
      </CModal>
    </>
  );
};

AppointmentsC.propTypes = {
  refresh: PropTypes.func.isRequired,
  selectedAppointments: PropTypes.object,
};

export default AppointmentsC;
